const { Map, List } = require('immutable');

// or using ES6 modules
// import { Map, List } from 'immutable';

const user = Map({
  id: 1,
  name: 'Alice',
  hobbies: List(['reading', 'gaming'])
});

console.log(user.toJS());
// Output: { id: 1, name: 'Alice', hobbies: ['reading', 'gaming'] }

const updatedUser = user.set('name', 'Bob');

console.log(user.get('name'));         // Alice
console.log(updatedUser.get('name'));  // Bob

const userWithMoreHobbies = user.update('hobbies', hobbies => hobbies.push('hiking'));

console.log(user.get('hobbies').toJS());          // ['reading', 'gaming']
console.log(userWithMoreHobbies.get('hobbies').toJS());  // ['reading', 'gaming', 'hiking']

const post = Map({
  id: 101,
  title: 'Building Scalable Data Models',
  content: 'Immutable.js helps manage data effectively.',
  comments: List([
    Map({ id: 1, text: 'Great post!' }),
    Map({ id: 2, text: 'Very helpful, thanks!' })
  ])
});

const newComment = Map({ id: 3, text: 'Nice explanation!' });
const updatedPost = post.update('comments', comments => comments.push(newComment));

console.log(post.get('comments').size);        // 2
console.log(updatedPost.get('comments').size); // 3

